class Trie01Vector {
private:
	struct TrieNode {
		array<int, 2> children; 
		int cnt;
		TrieNode() : children{ 0, 0 }, cnt(0) {}
	};

	vector<TrieNode> tr;
	int newNode() { 
		tr.push_back(TrieNode()); 
		return ++nodeCnt; 
	}

	int MAX; 	   
	int nodeCnt = 1;
	int root = 1;

public:
	Trie01Vector(int MAX) :MAX(MAX), tr(2) {}

	void insert(int num) {
		int now = root;
		tr[now].cnt++;

		for (int i = MAX; i >= 0; i--) {
			bool bit = (num >> i) & 1;
			if (not tr[now].children[bit]) {
				int tmp = newNode();
				tr[now].children[bit] = tmp;
			}
			now = tr[now].children[bit];
			tr[now].cnt++;
		}
	}

	vector<int> get_all(int now, int i, int pre) {
		// 获取 now 子树下，带上 pre 前缀的所有数
		var dfs = [&](var dfs, int now, int i, int pre)->vector<int> {
			var to = array<int, 2>{ tr[now].children[0], tr[now].children[1] };

			var res = vector<int>();
			if (to[0]) {
				var dr = dfs(dfs, to[0], i - 1, pre);
				res.insert(res.end(), all(dr));
			}
			if (to[1]) {
				var dr = dfs(dfs, to[1], i - 1, pre + (1ll << i));
				res.insert(res.end(), all(dr));
			}
			if (!to[0] and !to[1])res.pb(pre);

			return res;
			};
		return dfs(dfs, now, i, pre);
	}
	pii find_max(int now, int k, int pre, int x) {
		// 获取 now 子树下，带上 pre 前缀能跟 x 异或最大的数 y 以及异或值 maxXor
		int maxXor = 0, y = pre;
		fb(i, k, 0) {
			bool bit = (x >> i) & 1;
			if (tr[now].children[!bit]) {
				maxXor |= (1ll << i);
				if (!bit)y |= (1ll << i);
				now = tr[now].children[!bit];
			}
			else {
				if (bit)y |= (1ll << i);
				now = tr[now].children[bit];
			}
		}
		return { maxXor,y };
	}
	vector<int> get_ans(int V) {
		int hb = Math::log2(V);
		var dfs = [&](var dfs, int now, int i, int pre)->vector<int> {
			var to = array<int, 2>{ tr[now].children[0], tr[now].children[1] }; 
			if (i == hb) { // 到了最高位，树的两边只能拿一个数
				// 先把保底的 1 个拿了
				// 拿什么都可以，毕竟只有一个，不存在 XOR
				var baodi = vector<int>();
				if (to[0] and baodi.empty()) {
					var res = get_all(to[0], i - 1, pre);
					if (res.size())baodi.pb(res[0]);
				}
				if (to[1] and baodi.empty()) {
					var res = get_all(to[1], i - 1, pre + (1ll << i));
					if (res.size())baodi.pb(res[0]);
				}
				if (!to[0] and !to[1] and baodi.empty())baodi.pb(pre);

				if (to[0] and to[1]) {
					var res = get_all(to[0], i - 1, pre);
					for (int x : res) {
						var[maxXor, y] = find_max(to[1], i - 1, pre + (1ll << i), x);
						if ((maxXor | (1ll << i)) >= V)return { x, y };
					}
				}

				return baodi;
			}
			else { // 比最高位高，那两边合法的数都能拿
				var res = vector<int>();
				if (to[0]) {
					var dr = dfs(dfs, to[0], i - 1, pre);
					res.insert(res.end(), all(dr));
				}
				if (to[1]) {
					var dr = dfs(dfs, to[1], i - 1, pre + (1ll << i));
					res.insert(res.end(), all(dr));
				}
				if (!to[0] and !to[1])res.pb(pre);
				return res;
			}
			};
		return dfs(dfs, root, MAX, 0);
	}
};

